def en_uzun_yukselen(yukseklikler):
    if not yukseklikler:
        return 0
    dp = [1] * len(yukseklikler)
    for i in range(len(yukseklikler)):
        for j in range(i):
            if yukseklikler[j] < yukseklikler[i]:
                dp[i] = max(dp[i], dp[j] + 1)
    return max(dp)
